<script setup>
import { computed,onMounted,reactive,ref } from 'vue'
import { ElMessage,ElMessageBox } from 'element-plus'
import { ArrowRight } from '@element-plus/icons-vue'
import { getProductionlineList } from '@/api/prodectionLine'
import { getInspectionRouteList } from '@/api/inspectionRoute'
import { addInspectionRecord,batchDeleteInspectionRecord,completeInspectionRecord,getInspectionRecordPage,updateInspectionRecord } from '@/api/inspectionRecord'
import { extractPageData,extractRecordsArray } from '@/util/apiData'
const resultOptions=[{value:'-',label:'-'},{value:'ZC',label:'ZC-正常'},{value:'YC',label:'YC-异常'}]
const abnormalTypeOptions=[['01','01-磨损'],['02','02-松动'],['03','03-精度超标'],['04','04-开裂'],['05','05-损坏'],['06','06-其他']].map(([value,label])=>({value,label}))
const completionOptions=[{value:'',label:'全部'},{value:'N',label:'N-未完工'},{value:'Y',label:'Y-已完工'}]
const standardCategoryOptions=['定量','定性','01','02'].map(value=>({value,label:value}))
const cycleUnitOptions=['天','周','月','年','班','01','02','03','04'].map(value=>({value,label:value}))
const pageSizes=[10,20,50,100]
const treeLoading=ref(false),tableLoading=ref(false),saveLoading=ref(false),drawerVisible=ref(false),drawerMode=ref('create')
const lines=ref([]),expanded=ref([]),activeLineId=ref(''),activeRouteId=ref(''),routeOptions=ref([]),rows=ref([]),selectedRows=ref([])
const filters=reactive({planDateRange:[],completionFlag:'',partCode:'',partName:''})
const page=reactive({current:1,size:10,total:0})
const form=reactive({id:'',routeId:'',routeCode:'',routeName:'',planDate:'',currentResult:'-',abnormalType:'',abnormalPhenomenon:'',planSource:'DJ',standardCode:'',partCode:'',partName:'',inspectionPart:'',inspectionContent:'',implementationCycle:'',cycleUnit:'',qualitativeStandard:'',standardCategory:'',quantitativeStandard:'',unitOfMeasurement:'',upperLimit:'',lowerLimit:'',idLocationCode:'',idLocationName:'',abnormalContactSheet:'',completionFlag:'N',completedAt:''})
const activeLine=computed(()=>lines.value.find(v=>String(v.id)===String(activeLineId.value))||null)
const title=computed(()=>activeLine.value?.name||'点检实绩查询')
const isAbnormalResult=computed(()=>form.currentResult==='YC')
const mapLine=i=>({id:i.id,name:i.lineName||i.name||'',routes:[]})
const mapRoute=i=>({id:i.id,routeCode:i.routeCode||'',routeName:i.routeName||''})
const labelOf=(opts,val)=>opts.find(v=>v.value===val)?.label||val||''
const isExpanded=line=>expanded.value.includes(line.id)
function resetForm(){Object.assign(form,{id:'',routeId:'',routeCode:'',routeName:'',planDate:'',currentResult:'-',abnormalType:'',abnormalPhenomenon:'',planSource:'DJ',standardCode:'',partCode:'',partName:'',inspectionPart:'',inspectionContent:'',implementationCycle:'',cycleUnit:'',qualitativeStandard:'',standardCategory:'',quantitativeStandard:'',unitOfMeasurement:'',upperLimit:'',lowerLimit:'',idLocationCode:'',idLocationName:'',abnormalContactSheet:'',completionFlag:'N',completedAt:''})}
async function loadRoutes(line){const res=await getInspectionRouteList(line.id);line.routes=extractRecordsArray(res?.data).map(mapRoute);routeOptions.value=line.routes.slice()}
async function loadTable(){if(!activeLineId.value)return;tableLoading.value=true;try{const res=await getInspectionRecordPage({current:page.current,size:page.size,productionLineId:activeLineId.value,routeId:activeRouteId.value||undefined,planDateStart:filters.planDateRange?.[0]||undefined,planDateEnd:filters.planDateRange?.[1]||undefined,completionFlag:filters.completionFlag||undefined,partCode:filters.partCode||undefined,partName:filters.partName||undefined});const d=extractPageData(res);rows.value=d.records;page.total=d.total}catch(e){if(!e?.elMessageNotified)ElMessage.error('获取点检实绩失败')}finally{tableLoading.value=false}}
async function clickLine(line){activeLineId.value=line.id;activeRouteId.value='';if(!line.routes.length)await loadRoutes(line);if(!isExpanded(line))expanded.value.push(line.id);page.current=1;await loadTable()}
async function clickRoute(line,route){activeLineId.value=line.id;activeRouteId.value=route.id;if(!isExpanded(line))expanded.value.push(line.id);page.current=1;await loadTable()}
async function toggleLine(line){if(isExpanded(line))expanded.value=expanded.value.filter(id=>id!==line.id);else{if(!line.routes.length)await loadRoutes(line);expanded.value.push(line.id)}}
function onRouteChange(id){const r=routeOptions.value.find(v=>String(v.id)===String(id));form.routeCode=r?.routeCode||'';form.routeName=r?.routeName||''}
function openCreate(){if(!activeLineId.value)return ElMessage.warning('请先选择生产线');drawerMode.value='create';resetForm();drawerVisible.value=true}
function openEdit(){if(selectedRows.value.length!==1)return ElMessage.warning('请选择一条记录');drawerMode.value='edit';resetForm();Object.assign(form,selectedRows.value[0]);drawerVisible.value=true}
async function save(){if(!form.planDate)return ElMessage.warning('计划日期不能为空');if(!form.partCode)return ElMessage.warning('设备部位编码不能为空');if(isAbnormalResult.value&&!form.abnormalType)return ElMessage.warning('当前结果为异常时，异常类型不能为空');saveLoading.value=true;try{const payload={...form,productionLineId:activeLineId.value,routeId:form.routeId||undefined,abnormalType:isAbnormalResult.value?form.abnormalType||undefined:undefined,abnormalPhenomenon:isAbnormalResult.value?form.abnormalPhenomenon||undefined:undefined};if(drawerMode.value==='create')await addInspectionRecord(payload);else await updateInspectionRecord(payload);ElMessage.success('保存成功');drawerVisible.value=false;await loadTable()}catch(e){if(!e?.elMessageNotified)ElMessage.error('保存失败')}finally{saveLoading.value=false}}
async function removeRows(){if(!selectedRows.value.length)return ElMessage.warning('请至少选择一条记录');await ElMessageBox.confirm('确认删除选中记录吗？','提示',{type:'warning'});await batchDeleteInspectionRecord(selectedRows.value.map(v=>v.id));ElMessage.success('删除成功');await loadTable()}
async function finishRows(){if(!selectedRows.value.length)return ElMessage.warning('请至少选择一条记录');await completeInspectionRecord(selectedRows.value.map(v=>v.id));ElMessage.success('完工成功');await loadTable()}
async function loadLines(){treeLoading.value=true;try{const res=await getProductionlineList();lines.value=extractRecordsArray(res?.data).map(mapLine);if(lines.value.length)await clickLine(lines.value[0])}catch(e){if(!e?.elMessageNotified)ElMessage.error('获取生产线列表失败')}finally{treeLoading.value=false}}
onMounted(loadLines)
</script>
<template>
<div class="inspection-record-page"><aside class="tree-panel" v-loading="treeLoading"><div class="panel-header">组织结构树</div><el-scrollbar class="tree-scrollbar"><div v-for="line in lines" :key="line.id"><button type="button" class="tree-line" :class="{ 'is-active': String(activeLineId)===String(line.id)&&!activeRouteId }" @click="clickLine(line)"><span class="tree-line-toggle" @click.stop="toggleLine(line)"><el-icon class="tree-arrow" :class="{ 'is-expanded': isExpanded(line) }"><ArrowRight /></el-icon></span><span class="tree-line-label">{{ line.name||'未命名生产线' }}</span></button><div v-if="isExpanded(line)" class="route-list"><button v-for="route in line.routes" :key="route.id" type="button" class="route-item" :class="{ 'is-active': String(activeRouteId)===String(route.id) }" @click="clickRoute(line,route)">{{ route.routeName||route.routeCode||'未命名点检路线' }}</button><div v-if="!line.routes.length" class="route-empty">暂无点检路线</div></div></div></el-scrollbar></aside><section class="content-panel"><el-card shadow="never" class="content-card"><template #header><span>查询条件</span></template><el-form inline><el-form-item label="计划日期"><el-date-picker v-model="filters.planDateRange" type="daterange" value-format="YYYY-MM-DD" /></el-form-item><el-form-item label="完工标记"><el-select v-model="filters.completionFlag" clearable style="width:140px"><el-option v-for="item in completionOptions" :key="item.value" :label="item.label" :value="item.value" /></el-select></el-form-item><el-form-item label="设备部位编码"><el-input v-model="filters.partCode" clearable /></el-form-item><el-form-item label="设备部位名称"><el-input v-model="filters.partName" clearable /></el-form-item><el-form-item><el-button type="primary" @click="page.current=1;loadTable()">查询</el-button></el-form-item></el-form></el-card><el-card shadow="never" class="content-card"><template #header><div class="toolbar"><span>{{ title }}</span><div><el-button type="primary" @click="openCreate">增加</el-button><el-button @click="openEdit">修改</el-button><el-button type="danger" @click="removeRows">删除</el-button><el-button type="success" @click="finishRows">完工</el-button></div></div></template><div class="table-scroll"><el-table class="record-table" v-loading="tableLoading" :data="rows" border @selection-change="selectedRows=$event"><el-table-column type="selection" width="48" /><el-table-column prop="currentResult" label="当前结果" min-width="100"><template #default="s">{{ labelOf(resultOptions,s.row.currentResult) }}</template></el-table-column><el-table-column prop="abnormalType" label="异常类型" min-width="110"><template #default="s">{{ labelOf(abnormalTypeOptions,s.row.abnormalType) }}</template></el-table-column><el-table-column prop="abnormalPhenomenon" label="异常现象" min-width="140" /><el-table-column prop="routeCode" label="路线编号" min-width="120" /><el-table-column prop="routeName" label="路线名称" min-width="140" /><el-table-column prop="planSource" label="计划来源" min-width="100" /><el-table-column prop="standardCode" label="标准编号" min-width="140" /><el-table-column prop="partCode" label="设备部位编码" min-width="140" /><el-table-column prop="partName" label="设备部位名称" min-width="140" /><el-table-column prop="inspectionPart" label="点检部位" min-width="120" /><el-table-column prop="inspectionContent" label="点检内容" min-width="160" /><el-table-column prop="implementationCycle" label="周期" min-width="80" /><el-table-column prop="cycleUnit" label="周期单位" min-width="100" /><el-table-column prop="qualitativeStandard" label="定性标准" min-width="140" /><el-table-column prop="standardCategory" label="标准类别" min-width="110" /><el-table-column prop="quantitativeStandard" label="定量标准" min-width="140" /><el-table-column prop="unitOfMeasurement" label="计量单位" min-width="100" /><el-table-column prop="upperLimit" label="上限" min-width="90" /><el-table-column prop="lowerLimit" label="下限" min-width="90" /><el-table-column prop="idLocationCode" label="ID位置编码" min-width="120" /><el-table-column prop="idLocationName" label="ID位置名称" min-width="130" /><el-table-column prop="abnormalContactSheet" label="异常联络单" min-width="130" /><el-table-column prop="completedAt" label="完工日期" min-width="160" /><el-table-column prop="completionFlag" label="完工标记" min-width="100"><template #default="s">{{ labelOf(completionOptions,s.row.completionFlag) }}</template></el-table-column><el-table-column prop="createdAt" label="创建日期" min-width="160" /></el-table></div><div class="pagination-row"><el-pagination v-model:current-page="page.current" v-model:page-size="page.size" :page-sizes="pageSizes" background layout="total, sizes, prev, pager, next" :total="page.total" @current-change="loadTable" @size-change="page.current=1;loadTable()" /></div></el-card></section><el-drawer v-model="drawerVisible" :title="drawerMode==='create'?'新增点检实绩':'修改点检实绩'" size="760px"><el-form label-width="110px" class="drawer-form"><div class="drawer-grid drawer-grid-2"><el-form-item label="计划日期"><el-date-picker v-model="form.planDate" type="date" value-format="YYYY-MM-DD" style="width:100%" /></el-form-item><el-form-item label="当前结果"><el-select v-model="form.currentResult" style="width:100%"><el-option v-for="item in resultOptions" :key="item.value" :label="item.label" :value="item.value" /></el-select></el-form-item><el-form-item label="异常类型"><el-select v-model="form.abnormalType" clearable style="width:100%" :disabled="!isAbnormalResult"><el-option v-for="item in abnormalTypeOptions" :key="item.value" :label="item.label" :value="item.value" /></el-select></el-form-item><el-form-item label="点检路线"><el-select v-model="form.routeId" clearable style="width:100%" @change="onRouteChange"><el-option v-for="item in routeOptions" :key="item.id" :label="`${item.routeCode} - ${item.routeName}`" :value="item.id" /></el-select></el-form-item><el-form-item label="路线编号"><el-input v-model="form.routeCode" /></el-form-item><el-form-item label="路线名称"><el-input v-model="form.routeName" /></el-form-item><el-form-item label="计划来源"><el-input v-model="form.planSource" /></el-form-item><el-form-item label="标准编号"><el-input v-model="form.standardCode" /></el-form-item><el-form-item label="设备部位编码"><el-input v-model="form.partCode" /></el-form-item><el-form-item label="设备部位名称"><el-input v-model="form.partName" /></el-form-item><el-form-item label="点检部位"><el-input v-model="form.inspectionPart" /></el-form-item><el-form-item label="点检内容"><el-input v-model="form.inspectionContent" /></el-form-item><el-form-item label="周期"><el-input v-model="form.implementationCycle" /></el-form-item><el-form-item label="周期单位"><el-select v-model="form.cycleUnit" clearable filterable allow-create default-first-option style="width:100%"><el-option v-for="item in cycleUnitOptions" :key="item.value" :label="item.label" :value="item.value" /></el-select></el-form-item><el-form-item label="标准类别"><el-select v-model="form.standardCategory" clearable filterable allow-create default-first-option style="width:100%"><el-option v-for="item in standardCategoryOptions" :key="item.value" :label="item.label" :value="item.value" /></el-select></el-form-item><el-form-item label="计量单位"><el-input v-model="form.unitOfMeasurement" /></el-form-item><el-form-item label="上限"><el-input v-model="form.upperLimit" /></el-form-item><el-form-item label="下限"><el-input v-model="form.lowerLimit" /></el-form-item><el-form-item label="ID位置编码"><el-input v-model="form.idLocationCode" /></el-form-item><el-form-item label="ID位置名称"><el-input v-model="form.idLocationName" /></el-form-item><el-form-item label="异常联络单"><el-input v-model="form.abnormalContactSheet" /></el-form-item><el-form-item label="完工标记"><el-select v-model="form.completionFlag" style="width:100%"><el-option v-for="item in completionOptions.slice(1)" :key="item.value" :label="item.label" :value="item.value" /></el-select></el-form-item></div><el-form-item label="异常现象"><el-input v-model="form.abnormalPhenomenon" type="textarea" :rows="3" :disabled="!isAbnormalResult" /></el-form-item><el-form-item label="定性标准"><el-input v-model="form.qualitativeStandard" type="textarea" :rows="3" /></el-form-item><el-form-item label="定量标准"><el-input v-model="form.quantitativeStandard" type="textarea" :rows="3" /></el-form-item></el-form><template #footer><div class="drawer-footer"><el-button @click="drawerVisible=false">取消</el-button><el-button type="primary" :loading="saveLoading" @click="save">保存</el-button></div></template></el-drawer></div>
</template>
<style scoped>
.inspection-record-page{display:flex;gap:12px;min-height:calc(100vh - 120px)}.tree-panel{width:250px;flex:0 0 250px;background:#f7f9fc;border:1px solid #d9e3f0;border-radius:4px;overflow:hidden}.panel-header{height:36px;display:flex;align-items:center;padding:0 12px;font-size:13px;font-weight:600;color:#2f5b91;background:linear-gradient(180deg,#e8f2ff 0%,#d9ebff 100%);border-bottom:1px solid #d9e3f0}.tree-scrollbar{height:calc(100vh - 180px)}.tree-line,.route-item{width:100%;border:0;background:transparent;text-align:left;cursor:pointer}.tree-line{display:flex;align-items:center;min-height:34px;padding:0 10px 0 6px}.tree-line:hover,.route-item:hover{background:#edf5ff}.tree-line.is-active,.route-item.is-active{background:#e8f2ff;color:#2f5b91}.tree-line-toggle{display:inline-flex;align-items:center;justify-content:center;width:20px;height:20px;margin-right:4px}.tree-arrow.is-expanded{transform:rotate(90deg)}.tree-line-label{flex:1;min-width:0;font-size:13px;line-height:18px;word-break:break-all}.route-list{padding:0 0 4px 28px}.route-item,.route-empty{min-height:30px;padding:6px 10px;font-size:12px;line-height:18px}.route-empty{color:#a8abb2}.content-panel{flex:1;min-width:0}.content-card+.content-card{margin-top:12px}.toolbar,.drawer-footer{display:flex;justify-content:space-between;align-items:center}.table-scroll{width:100%;overflow-x:auto;overflow-y:hidden;padding-bottom:4px}.record-table{min-width:2700px}.pagination-row{display:flex;justify-content:flex-end;margin-top:12px}.drawer-form{padding-right:8px}.drawer-grid{display:grid;gap:0 16px}.drawer-grid-2{grid-template-columns:repeat(2,minmax(0,1fr))}:deep(.drawer-form .el-form-item){margin-bottom:18px}:deep(.drawer-form .el-textarea__inner){resize:vertical}
</style>
